mapper.select:
SELECT id, supplier_id, staff_photo, sample_room_photo, production_workshop_photo, packaging_workshop_photo, inspection_area_photo, factory_area_photo, gate_photo, other_photo, remark, created_by, created_at FROM supplier_visit_photo
AND id = #{id} AND supplier_id = #{supplierId} AND staff_photo LIKE CONCAT('%', #{staffPhoto}, '%') AND sample_room_photo LIKE CONCAT('%', #{sampleRoomPhoto}, '%') AND production_workshop_photo LIKE CONCAT('%', #{productionWorkshopPhoto}, '%') AND packaging_workshop_photo LIKE CONCAT('%', #{packagingWorkshopPhoto}, '%') AND inspection_area_photo LIKE CONCAT('%', #{inspectionAreaPhoto}, '%') AND factory_area_photo LIKE CONCAT('%', #{factoryAreaPhoto}, '%') AND gate_photo LIKE CONCAT('%', #{gatePhoto}, '%') AND other_photo LIKE CONCAT('%', #{otherPhoto}, '%') AND remark LIKE CONCAT('%', #{remark}, '%') AND created_by LIKE CONCAT('%', #{createdBy}, '%') AND created_at = #{createdAt}
ORDER BY created_at DESC
